#!/usr/bin/env bash
# Generated by bun-bench Harbor export adapter. Oracle reference solution.
# Overwrites the starter source under /app with the bun-bench reference.
set -euo pipefail

mkdir -p /app/src
cat > /app/src/server.ts <<'BUN_BENCH_SOLUTION_EOF'
const port = Number(Bun.env.PORT ?? 3000);

const MAX_ATTEMPTS = 3;
const BACKOFF_MS = 5;
const FAILURE_THRESHOLD = 5;
const COOLDOWN_MS = 500;

type Mode = "up" | "down" | "flaky";
type BreakerState = "closed" | "open" | "half_open";

// Simulated in-process dependency.
const dependency = {
  mode: "up" as Mode,
  calls: 0,
  invoke(): void {
    this.calls += 1;
    if (this.mode === "down" || this.mode === "flaky") {
      throw new Error("dependency_unavailable");
    }
  },
};

// Circuit breaker state.
const breaker = {
  state: "closed" as BreakerState,
  consecutiveFailures: 0,
  openedAt: 0,
};

function sleep(ms: number): Promise<void> {
  return new Promise((resolve) => setTimeout(resolve, ms));
}

// Resolve the effective breaker state, transitioning open -> half_open once the
// cooldown has elapsed.
function effectiveState(): BreakerState {
  if (breaker.state === "open" && Date.now() - breaker.openedAt >= COOLDOWN_MS) {
    breaker.state = "half_open";
  }
  return breaker.state;
}

function onCallSuccess(): void {
  breaker.consecutiveFailures = 0;
  breaker.state = "closed";
}

function onCallFailure(): void {
  breaker.consecutiveFailures += 1;
  if (breaker.state === "half_open") {
    // Trial failed: reopen and restart the cooldown.
    breaker.state = "open";
    breaker.openedAt = Date.now();
    return;
  }
  if (breaker.consecutiveFailures >= FAILURE_THRESHOLD) {
    breaker.state = "open";
    breaker.openedAt = Date.now();
  }
}

function circuitOpenResponse(): Response {
  return Response.json({ error: "circuit_open" }, { status: 503 });
}

// Attempt the dependency for an idempotent (GET) call: up to MAX_ATTEMPTS.
async function callWithRetry(): Promise<Response> {
  for (let attempt = 1; attempt <= MAX_ATTEMPTS; attempt += 1) {
    try {
      dependency.invoke();
      onCallSuccess();
      return Response.json({ ok: true, attempts: attempt }, { status: 200 });
    } catch {
      if (attempt < MAX_ATTEMPTS) await sleep(BACKOFF_MS);
    }
  }
  onCallFailure();
  return Response.json({ error: "upstream_failed", attempts: MAX_ATTEMPTS }, { status: 502 });
}

// Attempt the dependency for a non-idempotent (POST) call: at most once.
function callOnce(): Response {
  try {
    dependency.invoke();
    onCallSuccess();
    return Response.json({ ok: true, attempts: 1 }, { status: 200 });
  } catch {
    onCallFailure();
    return Response.json({ error: "upstream_failed", attempts: 1 }, { status: 502 });
  }
}

Bun.serve({
  port,
  async fetch(request) {
    const url = new URL(request.url);
    const path = url.pathname;

    if (request.method === "GET" && path === "/breaker") {
      const state = effectiveState();
      return Response.json(
        {
          state,
          consecutive_failures: breaker.consecutiveFailures,
          dependency_calls: dependency.calls,
        },
        { status: 200 },
      );
    }

    if (request.method === "POST" && path === "/dependency") {
      let body: unknown;
      try {
        body = await request.json();
      } catch {
        return Response.json({ error: "invalid_mode" }, { status: 400 });
      }
      const mode = (body as Record<string, unknown> | null)?.mode;
      if (mode !== "up" && mode !== "down" && mode !== "flaky") {
        return Response.json({ error: "invalid_mode" }, { status: 400 });
      }
      dependency.mode = mode;
      return Response.json({ mode }, { status: 200 });
    }

    if (path === "/call" && (request.method === "GET" || request.method === "POST")) {
      // Fail fast while the circuit is open.
      if (effectiveState() === "open") {
        return circuitOpenResponse();
      }
      if (request.method === "GET") {
        return await callWithRetry();
      }
      return callOnce();
    }

    return Response.json({ error: "not_found" }, { status: 404 });
  },
});

console.log(`circuit-breaker reference listening on ${port}`);
BUN_BENCH_SOLUTION_EOF
